    #[derive(Clone)]
    pub enum ChatAction {
        /// draftChanged
        CDraftChanged {
            draft: Rc<Option<Sequence<DafnyChar>>>
        },
        /// activityChanged
        CActivityChanged {
            activity: Rc<Option<Sequence<DafnyChar>>>
        },
        /// turnStarted → activeTurn; clears the auto-started pending message
        CTurnStarted {
            turnId: Sequence<DafnyChar>,
            message: Rc<Json>,
            queuedMessageId: Rc<Option<Sequence<DafnyChar>>>
        },
        /// turnComplete → force-cancel + finalize (no-op on wrong id)
        CTurnComplete {
            turnId: Sequence<DafnyChar>
        },
        /// turnCancelled → finalize with state "cancelled"
        CTurnCancelled {
            turnId: Sequence<DafnyChar>
        },
        /// usage → sets activeTurn.usage (no-op on wrong id)
        CUsage {
            turnId: Sequence<DafnyChar>,
            usage: Rc<Json>
        },
        /// error → finalize turn state "error", status Error
        CError {
            turnId: Sequence<DafnyChar>,
            err: Rc<Json>
        },
        /// responsePart → append markdown/reasoning part
        CResponsePart {
            turnId: Sequence<DafnyChar>,
            part: Rc<Part>
        },
        /// delta → accumulate content on a MARKDOWN part only
        CDelta {
            turnId: Sequence<DafnyChar>,
            partId: Sequence<DafnyChar>,
            content: Sequence<DafnyChar>
        },
        CToolCallStart {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            toolName: Sequence<DafnyChar>,
            displayName: Sequence<DafnyChar>,
            intention: Rc<Option<Sequence<DafnyChar>>>,
            contributor: Rc<Option<Rc<ToolCallContributor>>>,
            meta: Rc<Option<Rc<Json>>>
        },
        CToolCallDelta {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            content: Sequence<DafnyChar>,
            invocationMessage: Rc<Option<Sequence<DafnyChar>>>,
            meta: Rc<Option<Rc<Json>>>
        },
        CToolCallReady {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            invocationMessage: Rc<Option<Sequence<DafnyChar>>>,
            toolInput: Rc<Option<Sequence<DafnyChar>>>,
            confirmationTitle: Rc<Option<Rc<Json>>>,
            riskAssessment: Rc<Option<Rc<Json>>>,
            edits: Rc<Option<Rc<Json>>>,
            editable: Rc<Option<bool>>,
            options: Rc<Option<Sequence<Rc<Json>>>>,
            confirmed: Rc<Option<Sequence<DafnyChar>>>,
            meta: Rc<Option<Rc<Json>>>
        },
        CToolCallConfirmed {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            approved: bool,
            confirmedVal: Rc<Option<Sequence<DafnyChar>>>,
            reason: Rc<Option<Sequence<DafnyChar>>>,
            reasonMessage: Rc<Option<Rc<Json>>>,
            userSuggestion: Rc<Option<Rc<Json>>>,
            editedToolInput: Rc<Option<Sequence<DafnyChar>>>,
            selectedOptionId: Rc<Option<Sequence<DafnyChar>>>,
            meta: Rc<Option<Rc<Json>>>
        },
        CToolCallAuthRequired {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            auth: Rc<Json>,
            meta: Rc<Option<Rc<Json>>>
        },
        CToolCallAuthResolved {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            meta: Rc<Option<Rc<Json>>>
        },
        CToolCallComplete {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            success: bool,
            pastTenseMessage: Rc<Option<Sequence<DafnyChar>>>,
            resultContent: Rc<Option<Rc<Json>>>,
            structuredContent: Rc<Option<Rc<Json>>>,
            error: Rc<Option<Rc<Json>>>,
            requiresResultConfirmation: bool,
            meta: Rc<Option<Rc<Json>>>
        },
        /// pending-result-confirmation → (approved) completed | (denied) cancelled
        CToolCallResultConfirmed {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            approved: bool,
            meta: Rc<Option<Rc<Json>>>
        },
        /// sets content on a RUNNING tool call
        CToolCallContentChanged {
            turnId: Sequence<DafnyChar>,
            toolCallId: Sequence<DafnyChar>,
            newContent: Rc<Json>,
            meta: Rc<Option<Rc<Json>>>
        },
        /// reasoning → accumulate on a REASONING part only
        CReasoning {
            turnId: Sequence<DafnyChar>,
            partId: Sequence<DafnyChar>,
            content: Sequence<DafnyChar>
        },
        /// keep turns up to+incl turnId; None → clear all; drops active turn
        CTruncated {
            upToTurnId: Rc<Option<Sequence<DafnyChar>>>
        },
        /// reorder queuedMessages; unlisted appended in original order
        CQueuedReordered {
            order: Sequence<Sequence<DafnyChar>>
        },
        /// prepend older turns (dedup by id), set cursor
        CTurnsLoaded {
            loaded: Sequence<Rc<Turn>>,
            cursor: Rc<Option<Sequence<DafnyChar>>>
        },
        /// inputRequested → upsert request; recompute status
        CInputRequested {
            req: Rc<InputReq>
        },
        /// set/clear a draft answer (no-op unknown request)
        CInputAnswerChanged {
            requestId: Sequence<DafnyChar>,
            questionId: Sequence<DafnyChar>,
            answer: Rc<Option<Rc<Json>>>
        },
        /// resolve into active-turn history; remove request (no-op unknown)
        CInputCompleted {
            requestId: Sequence<DafnyChar>,
            response: Sequence<DafnyChar>,
            answers: Map<Sequence<DafnyChar>, Rc<Json>>
        },
        /// steering → steeringMessage; queued → queuedMessages upsert
        CPendingMessageSet {
            kind: Sequence<DafnyChar>,
            id: Sequence<DafnyChar>,
            message: Rc<Json>
        },
        /// steering → clear-if-match; queued → remove by id
        CPendingMessageRemoved {
            kind: Sequence<DafnyChar>,
            id: Sequence<DafnyChar>
        },
        CUnknown {
            raw: Rc<Json>
        }
    }

